    batch_size = x_1.shape[0]
    t_idx = torch.randint(0, len(alpha_bar), (batch_size,))
    a_bar = alpha_bar[t_idx].unsqueeze(-1).to(x_1.device)
    epsilon = torch.randn_like(x_1)
    x_t = torch.sqrt(a_bar) * x_1 + torch.sqrt(1 - a_bar) * epsilon
    pred_eps = noise_predictor(x_t, t_idx.float().to(x_1.device))
    return F.mse_loss(pred_eps, epsilon)

